{
  "name": "El-Sayed Taha | Interactive Profile",
  "description": "A high-end, dynamic, and 3D-animated personal profile and dashboard for El-Sayed Taha, featuring AI-powered skill management and immersive UI/UX.",
  "requestFramePermissions": [
    "camera"
  ]
}

export interface Skill {
  id: string;
  name: string;
  level: number; // 0-100
  category: 'Frontend' | 'Backend' | 'Design' | 'Soft Skills' | 'Other';
  description?: string;
}

export interface ProfileData {
  name: string;
  title: string;
  bio: string;
  skills: Skill[];
  profileImage?: string;
}

export enum AppMode {
  VIEW = 'view',
  EDIT = 'edit'
}

import { GoogleGenAI, Type } from "@google/genai";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

export const generateSkillDescription = async (skillName: string): Promise<string> => {
  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: `Generate a professional and brief description (in Arabic) for the skill: ${skillName}. Focus on how it adds value to a professional profile. Keep it under 100 characters.`,
      config: {
        temperature: 0.7,
      },
    });
    return response.text || "مهارة متميزة تساهم في تطوير المشاريع.";
  } catch (error) {
    console.error("Gemini Error:", error);
    return "مهارة متميزة تساهم في تطوير المشاريع.";
  }
};

export const chatWithAI = async (message: string, context: string): Promise<string> => {
  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: `You are an AI assistant for El-Sayed Taha's portfolio. 
      Context about El-Sayed: ${context}.
      User question: ${message}
      Answer in Arabic professionally.`,
    });
    return response.text || "عذراً، لم أستطع معالجة طلبك حالياً.";
  } catch (error) {
    console.error("Gemini Error:", error);
    return "عذراً، حدث خطأ ما.";
  }
};

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

import React, { useState, useEffect, useCallback, useRef } from 'react';
import { motion, AnimatePresence, useScroll, useTransform } from 'framer-motion';
import { 
  User, 
  Code, 
  Settings, 
  Plus, 
  Trash2, 
  Sparkles, 
  Github, 
  Linkedin, 
  Mail, 
  Edit3, 
  Eye, 
  Save,
  MessageSquare,
  ChevronRight,
  Monitor,
  Cpu,
  Layers
} from 'lucide-react';
import { Radar, RadarChart, PolarGrid, PolarAngleAxis, ResponsiveContainer } from 'recharts';
import { Skill, ProfileData, AppMode } from './types';
import { generateSkillDescription, chatWithAI } from './services/geminiService';

// Default Data
const INITIAL_DATA: ProfileData = {
  name: "السيد طه",
  title: "مهندس برمجيات وواجهات تفاعلية",
  bio: "مطور برمجيات شغوف ببناء تجارب مستخدم مذهلة تجمع بين الأداء العالي والتصميم الجذاب. أؤمن بأن البرمجة فن، والواجهة هي اللوحة.",
  skills: [
    { id: '1', name: 'React.js', level: 95, category: 'Frontend', description: 'بناء واجهات معقدة وسريعة.' },
    { id: '2', name: 'TypeScript', level: 90, category: 'Frontend', description: 'برمجة آمنة ومنظمة.' },
    { id: '3', name: 'Node.js', level: 85, category: 'Backend', description: 'تطوير خوادم قوية.' },
    { id: '4', name: 'Tailwind CSS', level: 98, category: 'Design', description: 'تصميم واجهات عصرية بلمح البصر.' },
