  profileImage: 'https://picsum.photos/seed/taha/400/400'
};

const App: React.FC = () => {
  const [profile, setProfile] = useState<ProfileData>(() => {
    const saved = localStorage.getItem('taha_profile');
    return saved ? JSON.parse(saved) : INITIAL_DATA;
  });
  const [mode, setMode] = useState<AppMode>(AppMode.VIEW);
  const [isAIChatOpen, setIsAIChatOpen] = useState(false);
  const [chatMessage, setChatMessage] = useState('');
  const [chatHistory, setChatHistory] = useState<{ role: 'user' | 'ai', text: string }[]>([]);
  const [isLoadingAI, setIsLoadingAI] = useState(false);

  useEffect(() => {
    localStorage.setItem('taha_profile', JSON.stringify(profile));
  }, [profile]);

  const { scrollYProgress } = useScroll();
  const scale = useTransform(scrollYProgress, [0, 1], [1, 1.2]);

  const handleAddSkill = async (name: string, category: Skill['category']) => {
    setIsLoadingAI(true);
    const description = await generateSkillDescription(name);
    const newSkill: Skill = {
      id: Date.now().toString(),
      name,
      level: 50,
      category,
      description
    };
    setProfile(prev => ({ ...prev, skills: [...prev.skills, newSkill] }));
    setIsLoadingAI(false);
  };

  const handleDeleteSkill = (id: string) => {
    setProfile(prev => ({ ...prev, skills: prev.skills.filter(s => s.id !== id) }));
  };

  const handleUpdateSkillLevel = (id: string, level: number) => {
    setProfile(prev => ({
      ...prev,
      skills: prev.skills.map(s => s.id === id ? { ...s, level } : s)
    }));
  };

  const handleSendMessage = async () => {
    if (!chatMessage.trim()) return;
    const userMsg = chatMessage;
    setChatHistory(prev => [...prev, { role: 'user', text: userMsg }]);
    setChatMessage('');
    setIsLoadingAI(true);

    const context = `El-Sayed Taha is a ${profile.title}. His bio: ${profile.bio}. His skills: ${profile.skills.map(s => s.name).join(', ')}.`;
    const aiResponse = await chatWithAI(userMsg, context);

    setChatHistory(prev => [...prev, { role: 'ai', text: aiResponse }]);
    setIsLoadingAI(false);
  };

  return (
    <div className="min-h-screen relative bg-gray-950 text-white selection:bg-blue-500/30">
      {/* Dynamic Background */}
      <div className="fixed inset-0 pointer-events-none overflow-hidden z-0">
        <div className="absolute top-[-10%] left-[-10%] w-[40%] h-[40%] bg-blue-600/10 blur-[120px] rounded-full animate-pulse" />
        <div className="absolute bottom-[-10%] right-[-10%] w-[40%] h-[40%] bg-purple-600/10 blur-[120px] rounded-full animate-pulse delay-700" />
        <div className="absolute top-[30%] right-[20%] w-[20%] h-[20%] bg-indigo-600/5 blur-[80px] rounded-full" />
      </div>

      {/* Navbar */}
      <nav className="fixed top-0 w-full z-50 glass px-6 py-4 flex items-center justify-between">
        <div className="flex items-center gap-3">
          <div className="w-10 h-10 bg-gradient-to-br from-blue-500 to-purple-600 rounded-xl flex items-center justify-center font-bold text-xl neon-glow">
            ST
