          <h1 className="text-xl font-bold tracking-tight hidden sm:block">السيد طه</h1>
        </div>
        <div className="flex items-center gap-4">
          <button 
            onClick={() => setMode(mode === AppMode.VIEW ? AppMode.EDIT : AppMode.VIEW)}
            className={`flex items-center gap-2 px-4 py-2 rounded-lg transition-all ${
              mode === AppMode.EDIT ? 'bg-green-600 hover:bg-green-700' : 'bg-blue-600 hover:bg-blue-700'
            }`}
          >
            {mode === AppMode.EDIT ? <Eye size={18} /> : <Edit3 size={18} />}
            <span className="font-medium">{mode === AppMode.EDIT ? 'عرض البروفايل' : 'تعديل البيانات'}</span>
          </button>
        </div>
      </nav>

      <main className="relative z-10 pt-28 pb-20 container mx-auto px-6">
        <AnimatePresence mode="wait">
          {mode === AppMode.VIEW ? (
            <motion.div 
              key="view"
              initial={{ opacity: 0, y: 20 }}
              animate={{ opacity: 1, y: 0 }}
              exit={{ opacity: 0, y: -20 }}
              className="space-y-20"
            >
              {/* Hero Section */}
              <section className="flex flex-col lg:flex-row items-center gap-12 lg:min-h-[70vh]">
                <div className="flex-1 space-y-6 text-center lg:text-right">
                  <motion.div
                    initial={{ scale: 0.9, opacity: 0 }}
                    animate={{ scale: 1, opacity: 1 }}
                    transition={{ duration: 0.5 }}
                  >
                    <span className="inline-block px-4 py-1 rounded-full bg-blue-500/10 text-blue-400 text-sm font-semibold mb-4 border border-blue-500/20">
                      متاح للعمل الحر والمشاريع الكبرى
                    </span>
                    <h2 className="text-5xl lg:text-7xl font-black gradient-text mb-4 leading-tight">
                      {profile.name}
                    </h2>
                    <h3 className="text-2xl lg:text-3xl text-gray-400 font-medium">
                      {profile.title}
                    </h3>
                  </motion.div>
                  <p className="text-lg text-gray-400 max-w-2xl mx-auto lg:mr-0 leading-relaxed">
                    {profile.bio}
                  </p>
                  <div className="flex items-center justify-center lg:justify-start gap-4 pt-4">
                    <button className="bg-white text-black px-8 py-3 rounded-full font-bold hover:bg-gray-200 transition-colors flex items-center gap-2">
                      تواصل معي <Mail size={18} />
                    </button>
                    <div className="flex items-center gap-3">
                      {[Github, Linkedin, Mail].map((Icon, i) => (
                        <a key={i} href="#" className="w-12 h-12 flex items-center justify-center rounded-full glass hover:border-blue-500/50 transition-all text-gray-400 hover:text-white">
                          <Icon size={20} />
                        </a>
                      ))}
                    </div>
                  </div>
                </div>

                <div className="flex-1 relative flex justify-center">
                  <motion.div 
                    style={{ perspective: 1000 }}
                    whileHover={{ rotateY: -10, rotateX: 5 }}
                    className="relative w-64 h-64 lg:w-96 lg:h-96"
                  >
                    <div className="absolute inset-0 bg-gradient-to-br from-blue-500 to-purple-600 rounded-3xl blur-2xl opacity-30 animate-pulse" />
                    <img 
                      src={profile.profileImage} 
                      alt={profile.name}
                      className="w-full h-full object-cover rounded-3xl border-2 border-white/10 glass z-10 relative"
                    />
                    <div className="absolute -bottom-6 -right-6 w-32 h-32 glass rounded-2xl flex flex-col items-center justify-center z-20 neon-glow">
                      <span className="text-3xl font-bold text-blue-400">+5</span>
