              </section>

              {/* Skills Visualization */}
              <section className="space-y-12">
                <div className="flex flex-col items-center gap-2">
                  <h4 className="text-3xl font-bold">لوحة المهارات</h4>
                  <div className="w-20 h-1 bg-blue-600 rounded-full" />
