                </div>
              </div>

              <div className="h-80 overflow-y-auto p-4 space-y-4 bg-black/20">
                {chatHistory.length === 0 && (
                  <p className="text-center text-gray-500 text-sm mt-10">أهلاً بك! أنا هنا لأخبرك المزيد عن مهارات وخبرات السيد طه.</p>
                )}
                {chatHistory.map((msg, i) => (
                  <div key={i} className={`flex ${msg.role === 'user' ? 'justify-start' : 'justify-end'}`}>
                    <div className={`max-w-[80%] px-4 py-2 rounded-2xl text-sm ${
                      msg.role === 'user' ? 'bg-gray-800' : 'bg-blue-600 text-white'
                    }`}>
                      {msg.text}
                    </div>
                  </div>
                ))}
                {isLoadingAI && (
                  <div className="flex justify-end">
                    <div className="bg-blue-600/20 px-4 py-2 rounded-2xl animate-pulse flex gap-1">
                      <div className="w-1.5 h-1.5 bg-blue-400 rounded-full animate-bounce" />
                      <div className="w-1.5 h-1.5 bg-blue-400 rounded-full animate-bounce [animation-delay:0.2s]" />
                      <div className="w-1.5 h-1.5 bg-blue-400 rounded-full animate-bounce [animation-delay:0.4s]" />
                    </div>
                  </div>
                )}
              </div>

              <div className="p-4 border-t border-white/10 flex gap-2 items-center">
                <input 
                  type="text" 
                  value={chatMessage}
                  onChange={(e) => setChatMessage(e.target.value)}
                  onKeyDown={(e) => e.key === 'Enter' && handleSendMessage()}
                  placeholder="اكتب سؤالك هنا..."
                  className="flex-1 bg-white/5 border border-white/10 rounded-full px-4 py-2 text-sm focus:outline-none focus:border-blue-500"
                />
                <button 
                  onClick={handleSendMessage}
                  disabled={isLoadingAI}
                  className="w-10 h-10 bg-blue-600 rounded-full flex items-center justify-center disabled:opacity-50"
                >
                  <ChevronRight size={18} className="rotate-180" />
                </button>
              </div>
            </motion.div>
          )}
        </AnimatePresence>
      </div>

      {/* Footer */}
      <footer className="relative z-10 py-10 text-center border-t border-white/5 glass">
        <p className="text-gray-500 text-sm">
          جميع الحقوق محفوظة © {new Date().getFullYear()} - <span className="text-blue-400 font-bold">السيد طه</span>
        </p>
      </footer>
    </div>
  );
};

export default App;

