export const generateSkillDescription = async (skillName: string): Promise<string> => {
  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: `Generate a professional business-oriented description (in Arabic) for the skill: ${skillName}. Focus on how this skill helps in business development, entrepreneurship, or AI implementation. Keep it under 100 characters.`,
      config: {
        temperature: 0.7,
      },
    });
    return response.text || "مهارة استراتيجية تهدف لتطوير الأعمال وزيادة الكفاءة.";
  } catch (error) {
    console.error("Gemini Error:", error);
    return "مهارة استراتيجية تهدف لتطوير الأعمال وزيادة الكفاءة.";
  }
};

