const Gallery3D: React.FC<{ images: string[] }> = ({ images }) => {
  const [index, setIndex] = useState(0);
  const containerRef = useRef<HTMLDivElement>(null);

  const rotate = useMotionValue(0);
  const springRotate = useSpring(rotate, { stiffness: 300, damping: 30 });

  const next = () => {
    setIndex((prev) => (prev + 1) % images.length);
    rotate.set(rotate.get() - (360 / images.length));
  };

  const prev = () => {
    setIndex((prev) => (prev - 1 + images.length) % images.length);
    rotate.set(rotate.get() + (360 / images.length));
  };

  return (
    <section className="py-24 space-y-16 overflow-hidden">
      <div className="text-center space-y-4">
        <h3 className="text-4xl lg:text-5xl font-black">معرض الرؤية الاستراتيجية</h3>
        <p className="text-slate-500">لحظات من العمل، الإلهام، والتطوير الريادي.</p>
      </div>

      <div className="relative h-[500px] flex items-center justify-center perspective-[2000px]">
        <motion.div 
          style={{ rotateY: springRotate, transformStyle: "preserve-3d" }}
          className="relative w-72 h-96 transition-all"
        >
          {images.map((img, i) => {
            const angle = (360 / images.length) * i;
            return (
              <motion.div
                key={i}
                style={{
                  transform: `rotateY(${angle}deg) translateZ(400px)`,
                  backfaceVisibility: "hidden",
                  position: "absolute",
                  inset: 0
                }}
                className="glass rounded-[2rem] overflow-hidden border-2 border-white/10 group cursor-pointer shadow-2xl"
              >
                <img src={img} className="w-full h-full object-cover transition-transform duration-500 group-hover:scale-110" />
                <div className="absolute inset-0 bg-gradient-to-t from-black/60 to-transparent opacity-0 group-hover:opacity-100 transition-opacity flex items-end p-6">
                   <button className="w-full py-2 glass rounded-xl text-xs font-bold flex items-center justify-center gap-2">
                     <Maximize2 size={14} /> عرض الصورة
                   </button>
                </div>
              </motion.div>
            );
          })}
        </motion.div>

        {/* Controls */}
        <div className="absolute bottom-0 flex gap-4">
          <button onClick={prev} className="w-14 h-14 glass rounded-2xl flex items-center justify-center hover:bg-emerald-500 hover:text-white transition-all">
            <ChevronRight className="rotate-180" size={24} />
          </button>
          <button onClick={next} className="w-14 h-14 glass rounded-2xl flex items-center justify-center hover:bg-emerald-500 hover:text-white transition-all">
            <ChevronRight size={24} />
          </button>
        </div>
      </div>
    </section>
  );
};

