                            <div className="h-2 w-full bg-slate-900 rounded-full overflow-hidden">
                              <motion.div initial={{ width: 0 }} whileInView={{ width: `${skill.level}%` }} transition={{ duration: 1.5, ease: "easeOut" }} className="h-full bg-gradient-to-r from-emerald-500 to-blue-600" />
                            </div>
                          </div>
                        </motion.div>
                      ))}
                    </div>
                  </div>
                </div>
              </section>

              {/* Strategic Projects Grid */}
              <section className="space-y-16">
                <div className="flex flex-col md:flex-row justify-between items-end gap-6 border-b border-white/5 pb-10">
                  <div className="space-y-4">
                    <h3 className="text-4xl md:text-5xl font-black">قصص النجاح الاستراتيجي</h3>
                    <p className="text-slate-400 text-lg md:text-xl max-w-2xl">تحويل البيانات والرؤى المجردة إلى نتائج ملموسة وأرقام حقيقية تنبض بالنمو.</p>
                  </div>
                  <button className="text-emerald-400 font-black text-sm flex items-center gap-2 group border-b-2 border-transparent hover:border-emerald-500 transition-all pb-1 mb-2">
                    تصفح الأرشيف الكامل <ChevronRight size={20} className="rotate-180 transition-transform group-hover:translate-x-[-4px]" />
                  </button>
                </div>

                <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-10">
                  {profile.projects.map(proj => (
                    <motion.div 
                      key={proj.id} 
                      whileHover={{ y: -12 }}
                      className="glass rounded-[3rem] overflow-hidden border-white/5 group shadow-2xl relative"
                    >
                      <div className="aspect-[16/10] overflow-hidden relative">
                        <img src={proj.image} className="w-full h-full object-cover transition-transform duration-1000 group-hover:scale-110" />
                        <div className="absolute inset-0 bg-gradient-to-t from-[#020617] via-transparent to-transparent opacity-90" />
                        <div className="absolute bottom-8 left-8 right-8">
                           <div className="text-[10px] font-black text-emerald-400 uppercase tracking-[0.3em] mb-3 bg-emerald-400/10 px-3 py-1 rounded-full w-fit backdrop-blur-md">{proj.impact}</div>
                           <h4 className="text-2xl md:text-3xl font-black leading-tight tracking-tight">{proj.title}</h4>
                        </div>
                      </div>
                      <div className="p-8 md:p-10 space-y-8">
                        <div className="flex flex-wrap gap-2.5">
                          {proj.tech.map(t => <span key={t} className="text-[10px] md:text-xs px-4 py-1.5 glass rounded-full text-slate-400 font-bold border-white/10 uppercase tracking-wider">{t}</span>)}
                        </div>
                        <motion.button 
                          whileHover={{ scale: 1.02 }}
                          whileTap={{ scale: 0.98 }}
                          className="w-full py-4.5 rounded-2xl bg-white text-black font-black text-sm md:text-base flex items-center justify-center gap-3 hover:bg-emerald-50 transition-all shadow-xl"
                        >
                          تحليل العائد الاستثماري <ArrowUpRight size={20} className="text-emerald-600" />
                        </motion.button>
                      </div>
                    </motion.div>
                  ))}
                </div>
              </section>

            </motion.div>
          ) : (
            <motion.div key="edit" initial={{ opacity: 0, scale: 0.98 }} animate={{ opacity: 1, scale: 1 }} className="max-w-5xl mx-auto glass p-6 md:p-16 rounded-[3rem] md:rounded-[4rem] space-y-16 mb-24 border-white/10 shadow-3xl">
               <div className="flex flex-col md:flex-row items-center justify-between gap-6 border-b border-white/10 pb-12">
                  <div className="text-center md:text-right">
                    <h2 className="text-4xl md:text-5xl font-black mb-2">غرفة القيادة</h2>
                    <p className="text-slate-500 font-medium text-lg tracking-wide">تحديث الهوية الاستراتيجية وتعديل المصفوفات.</p>
                  </div>
                  <div className="w-16 h-16 bg-blue-600/20 rounded-3xl flex items-center justify-center text-blue-500 border border-blue-500/30">
                    <Settings size={36} className="animate-spin-slow" />
                  </div>
               </div>

               {/* Profile Image Edit */}
               <section className="space-y-8">
                  <h3 className="text-2xl font-black flex items-center gap-3"><ImageIcon className="text-blue-500" /> صورة الملف الشخصي</h3>
                  <div className="flex flex-col lg:flex-row items-center gap-10 glass p-8 rounded-[2.5rem] border-white/10 shadow-lg">
                    <div className="w-32 h-32 md:w-40 md:h-40 rounded-[2rem] overflow-hidden border-2 border-emerald-500/50 shadow-2xl shrink-0">
                      <img src={profile.profileImage} className="w-full h-full object-cover bg-slate-900" />
                    </div>
                    <div className="flex-1 w-full space-y-4">
                      <label className="text-xs font-black uppercase text-slate-500 tracking-[0.2em] mb-2 block">رابط الصورة السحابي (URL)</label>
                      <div className="relative group">
                        <input 
                          value={profile.profileImage} 
                          onChange={e => setProfile({...profile, profileImage: e.target.value})} 
                          className="w-full glass bg-white/5 rounded-2xl px-14 py-4.5 outline-none border border-white/10 focus:border-emerald-500 transition-all font-mono text-sm group-hover:border-white/20" 
                          placeholder="https://images.unsplash.com/..."
                        />
                        <LinkIcon className="absolute left-5 top-1/2 -translate-y-1/2 text-slate-500" size={22} />
                      </div>
                    </div>
                  </div>
               </section>

               <div className="grid grid-cols-1 md:grid-cols-2 gap-10">
                  <div className="space-y-4">
                    <label className="text-xs font-black uppercase text-slate-500 tracking-[0.2em]">الاسم المهني الكامل</label>
                    <input value={profile.name} onChange={e => setProfile({...profile, name: e.target.value})} className="w-full glass bg-white/5 rounded-2xl px-8 py-5 outline-none border border-white/10 focus:border-emerald-500 transition-all font-bold text-lg" />
                  </div>
                  <div className="space-y-4">
                    <label className="text-xs font-black uppercase text-slate-500 tracking-[0.2em]">المسمى الاستراتيجي الرئيسي</label>
                    <input value={profile.title} onChange={e => setProfile({...profile, title: e.target.value})} className="w-full glass bg-white/5 rounded-2xl px-8 py-5 outline-none border border-white/10 focus:border-emerald-500 transition-all font-bold text-lg" />
                  </div>
               </div>

               <div className="space-y-4">
                  <label className="text-xs font-black uppercase text-slate-500 tracking-[0.2em]">الرسالة الاستراتيجية (Bio)</label>
                  <textarea rows={5} value={profile.bio} onChange={e => setProfile({...profile, bio: e.target.value})} className="w-full glass bg-white/5 rounded-3xl px-8 py-6 outline-none border border-white/10 focus:border-emerald-500 transition-all text-lg font-medium leading-relaxed resize-none" />
               </div>

               {/* Advanced Projects Manager */}
               <section className="space-y-10">
                  <div className="flex flex-col sm:flex-row justify-between items-center gap-4">
                    <h3 className="text-2xl font-black flex items-center gap-3"><Briefcase className="text-purple-500" /> إدارة قصص النجاح</h3>
                    <motion.button 
                      whileHover={{ scale: 1.05 }}
                      whileTap={{ scale: 0.95 }}
                      onClick={addProject} 
                      className="bg-purple-600 px-8 py-4 rounded-2xl text-sm font-black hover:bg-purple-500 transition-all shadow-xl shadow-purple-500/20"
                    >
                      + إضافة مشروع استراتيجي
                    </motion.button>
                  </div>
                  <div className="grid gap-8">
                    {profile.projects.map(p => (
                      <div key={p.id} className="glass p-8 md:p-10 rounded-[3rem] border border-white/10 space-y-8 relative group hover:border-purple-500/30 transition-all">
                        <button onClick={() => deleteProject(p.id)} className="absolute top-8 left-8 text-red-500/50 hover:text-red-500 transition-all hover:scale-125"><Trash2 size={24} /></button>
                        <div className="grid md:grid-cols-2 gap-10">
                          <div className="space-y-3">
                            <label className="text-xs font-bold text-slate-500 tracking-wider">عنوان المشروع</label>
                            <input value={p.title} onChange={e => updateProject(p.id, {title: e.target.value})} className="w-full bg-white/5 border border-white/10 rounded-2xl px-6 py-4 outline-none focus:border-purple-500 font-bold" />
                          </div>
                          <div className="space-y-3">
                            <label className="text-xs font-bold text-slate-500 tracking-wider">الأثر الاستراتيجي</label>
                            <input value={p.impact} onChange={e => updateProject(p.id, {impact: e.target.value})} className="w-full bg-white/5 border border-white/10 rounded-2xl px-6 py-4 outline-none focus:border-emerald-500 font-bold" />
                          </div>
                        </div>
                        <div className="grid md:grid-cols-2 gap-10">
                          <div className="space-y-3">
                            <label className="text-xs font-bold text-slate-500 tracking-wider">رابط صورة المعاينة</label>
                            <input value={p.image} onChange={e => updateProject(p.id, {image: e.target.value})} className="w-full bg-white/5 border border-white/10 rounded-2xl px-6 py-4 outline-none font-mono text-xs" />
                          </div>
                          <div className="space-y-3">
                            <label className="text-xs font-bold text-slate-500 tracking-wider">التقنيات والاستراتيجيات (فاصلة)</label>
                            <input 
                              value={p.tech.join(', ')} 
                              onChange={e => updateProject(p.id, {tech: e.target.value.split(',').map(t => t.trim())})} 
                              className="w-full bg-white/5 border border-white/10 rounded-2xl px-6 py-4 outline-none text-sm font-bold" 
                            />
                          </div>
                        </div>
                      </div>
                    ))}
                  </div>
               </section>
            </motion.div>
          )}
        </AnimatePresence>
      </main>

      {/* AI Bot - Refined High-End UI */}
      <div className="fixed bottom-6 left-6 md:bottom-12 md:left-12 z-[100]">
        <motion.button 
          whileHover={{ scale: 1.1, rotate: -12 }}
          whileTap={{ scale: 0.9 }}
          onClick={() => setIsAIChatOpen(!isAIChatOpen)} 
          className="w-16 h-16 md:w-22 md:h-22 bg-emerald-600 rounded-[2rem] md:rounded-[2.5rem] flex items-center justify-center shadow-3xl shadow-emerald-500/40 relative group"
        >
          {isAIChatOpen ? <X size={28} className="text-white" /> : <Sparkles size={28} className="text-white group-hover:scale-125 transition-transform" />}
          {!isAIChatOpen && <div className="absolute -top-1 -right-1 w-6 h-6 bg-blue-500 rounded-full border-4 border-[#020617] animate-bounce" />}
        </motion.button>

        <AnimatePresence>
          {isAIChatOpen && (
            <motion.div 
              initial={{ opacity: 0, x: -40, y: 40, scale: 0.85, rotate: -2 }} 
              animate={{ opacity: 1, x: 0, y: 0, scale: 1, rotate: 0 }} 
              exit={{ opacity: 0, x: -40, y: 40, scale: 0.85, rotate: -2 }} 
              className="absolute bottom-20 md:bottom-28 left-0 w-[340px] md:w-[480px] max-w-[calc(100vw-48px)] glass rounded-[2.5rem] md:rounded-[3.5rem] overflow-hidden flex flex-col shadow-4xl border-emerald-500/30"
            >
              <div className="p-8 md:p-10 bg-emerald-600/10 border-b border-white/10 flex items-center gap-5">
                <div className="w-14 h-14 md:w-16 md:h-16 rounded-2xl bg-emerald-600 flex items-center justify-center shadow-lg"><MessageSquare size={28} /></div>
                <div>
                  <h4 className="font-black text-xl md:text-2xl">المستشار الذكي للسيد طه</h4>
                  <p className="text-[10px] md:text-[11px] text-emerald-400 font-black uppercase tracking-[0.2em] mt-1">مدعوم بتقنيات Gemini الاستراتيجية</p>
                </div>
              </div>
              <div className="h-[350px] md:h-[450px] overflow-y-auto p-8 md:p-10 space-y-8 bg-slate-900/30 custom-scrollbar">
                {chatHistory.length === 0 && (
                  <div className="text-center py-12 space-y-6">
                    <div className="w-16 h-16 bg-white/5 rounded-full flex items-center justify-center mx-auto"><Lightbulb className="text-emerald-400" size={32} /></div>
                    <p className="text-slate-400 font-medium text-lg leading-relaxed">أهلاً بك في فضاء السيد طه الاستراتيجي. كيف يمكنني مساعدتك اليوم في استشراف آفاق النمو لعملك؟</p>
                  </div>
                )}
                {chatHistory.map((m, i) => (
                  <div key={i} className={`flex ${m.role === 'user' ? 'justify-start' : 'justify-end'}`}>
                    <div className={`max-w-[85%] px-7 py-5 rounded-[2rem] text-sm md:text-base leading-relaxed font-medium shadow-xl ${m.role === 'user' ? 'bg-slate-800 text-slate-200 rounded-tl-none' : 'bg-emerald-600 text-white shadow-emerald-500/20 rounded-tr-none'}`}>{m.text}</div>
                  </div>
                ))}
                {isLoadingAI && <div className="flex justify-end animate-pulse"><div className="bg-emerald-600/20 w-20 h-12 rounded-[1.5rem]" /></div>}
              </div>
              <div className="p-8 md:p-10 border-t border-white/10 flex gap-4 bg-slate-900/40">
                <input 
                  value={chatMessage} 
                  onChange={e => setChatMessage(e.target.value)} 
                  onKeyDown={e => e.key === 'Enter' && handleSendMessage()} 
                  placeholder="اسأل المستشار عن فرص الابتكار..." 
                  className="flex-1 glass bg-white/5 rounded-2xl px-7 py-5 text-sm md:text-base outline-none focus:border-emerald-500 transition-all font-medium placeholder:text-slate-600" 
                />
                <button 
                  onClick={handleSendMessage} 
                  className="w-14 h-14 md:w-16 md:h-16 bg-emerald-600 rounded-2xl flex items-center justify-center active:scale-90 transition-all shadow-xl shadow-emerald-500/30"
                >
                  <ChevronRight size={28} />
                </button>
              </div>
            </motion.div>
          )}
        </AnimatePresence>
      </div>

      <footer className="relative z-10 py-20 md:py-32 text-center border-t border-white/5 glass">
        <div className="max-w-7xl mx-auto px-6 flex flex-col md:flex-row justify-between items-center gap-12">
          <div className="text-center md:text-right space-y-4">
             <h5 className="text-3xl md:text-4xl font-black gradient-text tracking-tighter">السيد طه</h5>
             <p className="text-slate-500 text-sm font-black uppercase tracking-[0.4em]">Business Strategy & AI Solutions</p>
          </div>
          <div className="flex gap-8 items-center text-slate-600 text-sm font-bold">
            <a href="#" className="hover:text-emerald-500 transition-colors">استراتيجيات</a>
            <a href="#" className="hover:text-emerald-500 transition-colors">عن الشركة</a>
            <a href="#" className="hover:text-emerald-500 transition-colors">تواصل</a>
          </div>
          <p className="text-slate-600 text-xs font-black uppercase tracking-widest">© {new Date().getFullYear()} طه ديزاين ستوديو الاستراتيجي.</p>
        </div>
      </footer>
    </div>
  );
};

export default App;
